### Build Sunburst Chart with Recharts for Hierarchical Data

Source: https://context7.com/recharts/recharts/llms.txt

Creates a hierarchical radial visualization showing parent-child relationships in a circular layout with nested rings. Displays multi-level categorical data with color-coded segments representing different branches. Dependencies include React and Recharts SunburstChart component. Input requires nested data structure with name, value, fill, and children properties.

```jsx
import React from 'react';
import { SunburstChart, ResponsiveContainer } from 'recharts';

const data = {
  name: 'Root',
  children: [
    {
      name: 'Sales',
      value: 4000,
      fill: '#8884d8',
      children: [
        { name: 'Q1', value: 1200, fill: '#8884d8' },
        { name: 'Q2', value: 1000, fill: '#83a6ed' },
        { name: 'Q3', value: 900, fill: '#8dd1e1' },
        { name: 'Q4', value: 900, fill: '#82ca9d' },
      ],
    },
    {
      name: 'Marketing',
      value: 3000,
      fill: '#82ca9d',
      children: [
        { name: 'Digital', value: 1800, fill: '#82ca9d' },
        { name: 'Print', value: 700, fill: '#a4de6c' },
        { name: 'Events', value: 500, fill: '#d0ed57' },
      ],
    },
    {
      name: 'Engineering',
      value: 5000,
      fill: '#ffc658',
      children: [
        { name: 'Frontend', value: 2000, fill: '#ffc658' },
        { name: 'Backend', value: 2200, fill: '#ffb347' },
        { name: 'DevOps', value: 800, fill: '#ff9c33' },
      ],
    },
  ],
};

function SunburstExample() {
  return (
    <ResponsiveContainer width="100%" height={400}>
      <SunburstChart
        data={data}
        dataKey="value"
        fill="#8884d8"
        startAngle={0}
        endAngle={360}
        innerRadius="20%"
        outerRadius="80%"
      />
    </ResponsiveContainer>
  );
}

export default SunburstExample;
```

